noncompliant:
// Noncompliant: No curly braces
if (condition)
    ExecuteSomething();
    CheckSomething(); // This is always executed!

// Noncompliant: for loop without braces
for (int i = 0; i < 10; i++)
    DoSomething(i);

compliant:
// Compliant: Using curly braces
if (condition)
{
    ExecuteSomething();
    CheckSomething();
}

// Compliant: for loop with braces
for (int i = 0; i < 10; i++)
{
    DoSomething(i);
}
